#include <cstdio>
#include <iostream>
#include <iomanip>
#include <cmath>
#include <limits>
#include <ctime>
#include <chrono>
#include <cuda_runtime.h>
#include <device_launch_parameters.h>

#define N 2048

#define IDX(i, j) ((i) + (j) * N)

void check_cuda_error(cudaError_t err, const char* msg) {
    if (err != cudaSuccess) {
        std::cerr << "CUDA Error: " << msg << " - " << cudaGetErrorString(err) << std::endl;
        exit(-1);
    }
}

__global__ void initialize_data_kernel(float* f) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int j = blockIdx.y * blockDim.y + threadIdx.y;

    if (i < N && j < N) {
        if (i == 0 || i == N-1) {
            f[IDX(i,j)] = sinf(j * 2.0f * M_PI / (N - 1));
        }
        else if (j == 0 || j == N-1) {
            f[IDX(i,j)] = sinf(i * 2.0f * M_PI / (N - 1));
        }
        else {
            f[IDX(i,j)] = 0.0f;
        }
    }
}

__global__ void compute_step_kernel(const float* f_old, float* f, float* error_ptr) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int j = blockIdx.y * blockDim.y + threadIdx.y;

    if (i >= 1 && i <= N-2 && j >= 1 && j <= N-2) {
        float t = 0.25f * (f_old[IDX(i-1,j)] +
                           f_old[IDX(i+1,j)] +
                           f_old[IDX(i,j-1)] +
                           f_old[IDX(i,j+1]);
        float df = t - f_old[IDX(i, j)];
        f[IDX(i,j)] = t;

        // Use atomic add for the reduction
        atomicAdd(error_ptr, df * df);
    }
}

__global__ void copy_back_kernel(const float* f, float* f_old) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int j = blockIdx.y * blockDim.y + threadIdx.y;

    if (i >= 1 && i <= N-2 && j >= 1 && j <= N-2) {
        f_old[IDX(i,j)] = f[IDX(i,j)];
    }
}

void initialize_data_host(float* f) {
    dim3 block(32, 32);
    dim3 grid((N + block.x - 1) / block.x, (N + block.y - 1) / block.y);

    initialize_data_kernel<<<grid, block>>>(f);
    check_cuda_error(cudaDeviceSynchronize(), "init sync");
}

int main () {

  auto start_time = std::chrono::steady_clock::now();

  float* f_host = (float*) aligned_alloc(64, N * N * sizeof(float));
  float* f_old_host = (float*) aligned_alloc(64, N * N * sizeof(float));

  float error = std::numeric_limits<float>::max();
  const float tolerance = 1.e-5f;

  // Allocate device memory
  float* f_dev;
  float* f_old_dev;
  float* error_dev;

  check_cuda_error(cudaMalloc(&f_dev, N * N * sizeof(float)), "malloc f");
  check_cuda_error(cudaMalloc(&f_old_dev, N * N * sizeof(float)), "malloc f_old");
  check_cuda_error(cudaMalloc(&error_dev, sizeof(float)), "malloc error");

  // Initialize host data
  initialize_data_host(f_host);
  initialize_data_host(f_old_host);

  // Copy initial data to device
  check_cuda_error(cudaMemcpy(f_dev, f_host, N * N * sizeof(float), cudaMemcpyHostToDevice), "copy f init");
  check_cuda_error(cudaMemcpy(f_old_dev, f_old_host, N * N * sizeof(float), cudaMemcpyHostToDevice), "copy f_old init");

  const int max_iters = 10000;
  int num_iters = 0;

  dim3 block(16, 16); // 256 threads per block
  dim3 grid((N + block.x - 1) / block.x, (N + block.y - 1) / block.y);

  auto start = std::chrono::steady_clock::now();

  while (error > tolerance && num_iters < max_iters) {

    error = 0.f;
    check_cuda_error(cudaMemcpy(error_dev, &error, sizeof(float), cudaMemcpyHostToDevice), "copy error init");

    compute_step_kernel<<<grid, block>>>(f_old_dev, f_dev, error_dev);
    check_cuda_error(cudaDeviceSynchronize(), "compute sync");

    check_cuda_error(cudaMemcpy(&error, error_dev, sizeof(float), cudaMemcpyDeviceToHost), "copy error result");

    copy_back_kernel<<<grid, block>>>(f_dev, f_old_dev);
    check_cuda_error(cudaDeviceSynchronize(), "copy sync");

    error = sqrtf(error / (N * N));

    if (num_iters % 1000 == 0) {
      std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
    }

    ++num_iters;
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

  if (error <= tolerance && num_iters < max_iters) {
    std::cout << "PASS" << std::endl;
  }
  else {
    std::cout << "FAIL" << std::endl;
    cudaFree(f_dev);
    cudaFree(f_old_dev);
    cudaFree(error_dev);
    free(f_host);
    free(f_old_host);
    return -1;
  }

  cudaFree(f_dev);
  cudaFree(f_old_dev);
  cudaFree(error_dev);
  free(f_host);
  free(f_old_host);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}
